{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.junit.jupiter.api.Test

class IndentationRuleReproTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `fun foo does NOT throw violation on last line when not indented`() {
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
            $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `fun foo2 does NOT throw violation on last line when not indented`() {
        val code =
            """
            fun foo2(): String {
                return $MULTILINE_STRING_QUOTE
                    <!--suppress XmlUnusedNamespaceDeclaration -->
                    <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `val foo does NOT throw violation on last line when not indented`() {
        val code =
            """
            val foo = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
            $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `fun foo throws violation on last line when indented`() {
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code)
            .hasLintViolation(4, 5, "Unexpected indent of multiline string closing quotes")
    }

    @Test
    fun `val foo throws violation on last line when indented`() {
        val code =
            """
            val foo = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code)
            .hasLintViolation(4, 5, "Unexpected indent of multiline string closing quotes")
    }
}
